    LANGUAGE plpgsql
    AS $$
BEGIN
    IF TG_OP = 'UPDATE' AND OLD.amount != NEW.amount THEN
        INSERT INTO "rateHistory" ("rateId", "oldAmount", "newAmount", "changedBy")
        VALUES (NEW.id, OLD.amount, NEW.amount, NEW."createdBy");
    END IF;
    RETURN NEW;
END;
$$;


